// Function node code
console.log('Initial data:', JSON.stringify(items, null, 2));

// Get the first item since n8n usually wraps data in an array
const data = items[0].json;
console.log('Data structure:', JSON.stringify(data, null, 2));

// Now process the people data
const people = data.people || [];

try {
  return people.map(person => {
    console.log('Processing person:', JSON.stringify(person, null, 2));
    return {
      json: {
        firstName: person.first_name || '',
        lastName: person.last_name || '',
        email: person.email || '',
        websiteUrl: person.website_url || '',
        linkedinUrl: person.linkedin_url || '',
        twitterUrl: person.twitter_url || '',
        facebookUrl: person.facebook_url || '',
        phone: person.primary_phone?.number || '',
        company: {
          name: person.company_name || '',
          domain: person.primary_domain || '',
          foundedYear: person.founded_year || '',
          logo: person.logo_url || ''
        },
        professional: {
          departments: person.departments || [],
          seniority: person.seniority || '',
          functions: person.functions || []
        }
      }
    };
  });
} catch (error) {
  console.log('Error occurred. Full items:', JSON.stringify(items, null, 2));
  throw new Error(`Error processing data: ${error.message}`);
}

// Function node to extract specific fields from Apollo response
try {
    const results = items.map(item => {
        const person = item.json.person; // Access the person object directly

        return {
            json: {
                firstName: person.first_name || '',
                lastName: person.last_name || '',
                email: person.email || '',
                linkedinUrl: person.linkedin_url || '',
                title: person.title || '',
                twitter: person.twitter_url || '',
                facebook: person.facebook_url || '',
                organizationName: person.employment_history?.[0]?.organization_name || '', // Get current organization from employment history
                headline: person.headline || '',
                photoUrl: person.photo_url || ''
            }
        };
    });

    console.log(`Successfully processed ${results.length} records`);
    return results;

} catch (error) {
    console.error('Error processing data:', error);
    throw new Error(`Failed to process data: ${error.message}`);
}
